1	-- CourtOps Tennis — expand certification types to the real USTA set:
2	--   roving official, chair umpire, tournament referee, deputy referee,
3	--   referee in training.
4	-- Rename the three existing short values (data keeps working) and add two more.
5	
6	ALTER TYPE certification_type RENAME VALUE 'roving'  TO 'roving_official';
7	ALTER TYPE certification_type RENAME VALUE 'chair'   TO 'chair_umpire';
8	ALTER TYPE certification_type RENAME VALUE 'referee' TO 'tournament_referee';
9	ALTER TYPE certification_type ADD VALUE IF NOT EXISTS 'deputy_referee';
10	ALTER TYPE certification_type ADD VALUE IF NOT EXISTS 'referee_in_training';
